
.tabs {
  display: flex;
  background-color: var(--c-abyss);
  border-bottom: 1px solid var(--c-gold-dim);
}

.tab-button {
  flex: 1;
  padding: 8px;
  border: none;
  background: transparent;
  color: var(--c-gold-dim);
  font-size: 0.92rem;
  font-weight: bold;
  font-family: var(--font-body);
  cursor: pointer;
  transition: all 0.2s;
  text-transform: uppercase;
  letter-spacing: 1px;
  border-right: 1px solid var(--c-gold-dark);
  text-shadow: none;
}

.tab-button:last-child {
  border-right: none;
}

.tab-button:hover {
  background-color: var(--c-dark-surface);
  color: var(--c-gold-light);
  text-shadow: 0 0 6px var(--c-gold-glow);
}

.tab-button.active {
  background-color: var(--c-charcoal);
  color: var(--c-gold);
  position: relative;
  top: 1px;
  padding-bottom: 10px;
  text-shadow: 0 0 8px var(--c-gold-glow);

  &::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    height: 2px;
    background: linear-gradient(90deg, transparent, var(--c-gold), transparent);
  }
}
