
.world-section {
  border-bottom: 1px solid var(--c-gold-dim);
  padding: 10px;
  background-color: var(--c-charcoal);
}

.meta-row {
  display: flex;
  justify-content: space-between;
  margin-bottom: 6px;
  font-weight: bold;
  font-size: 0.9rem;
  font-family: var(--font-title);
  color: var(--c-gold-light);
  letter-spacing: 1px;
  border-bottom: 1px dashed var(--c-gold-dark);
  padding-bottom: 6px;
  flex-wrap: wrap;
  gap: 6px;
  text-shadow: 0 0 4px var(--c-gold-glow);
}

.event-list {
  display: flex;
  gap: 8px;
  overflow-x: auto;
}

.event-badge {
  background: var(--c-dark-surface);
  border: 1px solid var(--c-gold-dark);
  padding: 6px 8px;
  min-width: 130px;
  flex: 1;
  position: relative;
}

.event-badge::before {
  content: '';
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  width: 3px;
  background: linear-gradient(180deg, var(--c-gold), var(--c-gold-dark));
}

.event-title {
  display: block;
  font-weight: bold;
  margin-bottom: 2px;
  padding-left: 8px;
  color: var(--c-white);
}

.event-desc {
  display: block;
  font-size: 0.75rem;
  color: var(--c-ghost);
  padding-left: 8px;
}

@media (max-width: 600px) {
  .meta-row {
    flex-direction: column;
    gap: 5px;
  }

  .event-list {
    flex-direction: column;
  }

  .event-badge {
    min-width: auto;
  }
}
